class ChatGateway { /* 请编写 */ }

NODE-015.reference:
@WebSocketGateway()
class ChatGateway {
  constructor(redisClient) {
    this.redis = redisClient;
    this.redis.subscribe("chat");
    this.redis.on("message", (channel, msg) => {
      this.server.emit("broadcast", JSON.parse(msg));
    });
  }

  @SubscribeMessage("message")
  handleMessage(client, payload) {
    this.redis.publish("chat", JSON.stringify(payload));
    return { event: "ack", data: "ok" };
  }

  afterInit(server) {
    this.server = server;
  }
}

