const amqp = require("amqplib");

async function producer() {
  const conn = await amqp.connect("amqp://localhost");
  const ch = await conn.createChannel();
  await ch.assertExchange("tasks", "direct", { durable: true });
  ch.publish("tasks", "email", Buffer.from(JSON.stringify({ to: "user@test.com", subject: "Hello" })));
  console.log("消息已发送");
  await conn.close();
}

async function consumer() {
  const conn = await amqp.connect("amqp://localhost");
  const ch = await conn.createChannel();
  const q = await ch.assertQueue("email_queue", { durable: true });
  ch.bindQueue(q.queue, "tasks", "email");
  ch.consume(q.queue, (msg) => {
    const data = JSON.parse(msg.content.toString());
    console.log("处理:", data);
    ch.ack(msg);
  });
}

producer();

