function evaluateOrm() {
  const dimensions = ["学习曲线", "类型安全", "查询性能", "社区生态", "迁移工具", "文档质量"];

  const typeorm = { name: "TypeORM", scores: { 学习曲线: 7, 类型安全: 6, 查询性能: 7, 社区生态: 8, 迁移工具: 6, 文档质量: 6 } };
  const prisma = { name: "Prisma", scores: { 学习曲线: 8, 类型安全: 9, 查询性能: 8, 社区生态: 9, 迁移工具: 9, 文档质量: 9 } };

  function avgScore(orm) {
    const vals = Object.values(orm.scores);
    return vals.reduce((a, b) => a + b, 0) / vals.length;
  }

  console.log("评估维度:", dimensions.join(", "));
  console.log(`${typeorm.name} 均分: ${avgScore(typeorm).toFixed(1)}`);
  console.log(`${prisma.name} 均分: ${avgScore(prisma).toFixed(1)}`);
  console.log("推荐:", avgScore(prisma) > avgScore(typeorm) ? prisma.name : typeorm.name);
  return avgScore(prisma) > avgScore(typeorm) ? prisma : typeorm;
}

