// AI 生成的初始代码（可能有 bug）
function debounceAI(fn, delay) {
  let timer;
  return function(...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn(...args), delay);
  };
}

// 审查发现的问题：
// 1. this 指向丢失 — 箭头函数不能用 call/apply
// 2. 没有取消防抖的能力

// 改进后代码
function debounceImproved(fn, delay) {
  let timer;
  const debounced = function(...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
  debounced.cancel = () => {
    clearTimeout(timer);
    timer = null;
  };
  return debounced;
}

// 测试
