// 1. 实现 SWR 风格的缓存获取
// 2. 对比 SSR vs CSR vs ISR

REACT-021.reference:
const cache = new Map<string, { data: any; ts: number }>();
async function swrFetch(key: string, fetcher: () => Promise<any>, maxAge = 60000) {
  const entry = cache.get(key);
  if (entry && Date.now() - entry.ts < maxAge) {
    console.log("缓存命中:", key);
    return entry.data;
  }
  const data = await fetcher();
  cache.set(key, { data, ts: Date.now() });
  console.log("数据获取:", key);
  return data;
}
console.log("SSR: 服务端渲染, CSR: 客户端渲染, ISR: 增量静态再生");

