// 2. 定义 AI 生成代码的审查标准

VIBE-015.reference:
const qualityGate = {
  必须: ["类型覆盖率 > 80%", "无 any 类型", "所有函数有 JSDoc", "单测覆盖率 > 70%"],
  禁止: ["any 类型", "console.log 在生产代码", "未处理的 Promise", "硬编码密钥"],
};
function checkGate(code: string, gate: typeof qualityGate) {
  const violations = gate.禁止.filter(r => code.includes(r.split(" ")[0]));
  return { violations, approved: violations.length === 0 };
}
const result = checkGate("function add(a: number, b: number): number { return a + b; }", qualityGate);
console.log("质量门禁:", JSON.stringify(result));

